const response = $input.first().json;
const workflows = response.data || [];
return workflows.filter(wf => !wf.isArchived).map(wf => ({
  json: {
    ...wf,
    tags: (wf.tags && wf.tags.length > 0) ? wf.tags : [{ id: 'sin-tag', name: 'sin-tag' }]
  }
}));

